CREATE OR REPLACE FUNCTION OFSERM.BANKING_OD_EXPOSURE_DATA_CREATION(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FSI_CAP_BANKING_EXPOSURES(N_COUNTRY_SKEY,N_CREDIT_LINE_SKEY,N_CREDIT_STATUS_SKEY,N_MIS_DATE_SKEY,N_ACCT_SKEY,N_GAAP_SKEY,N_ISSUE_SKEY,N_OCCUPANCY_TYPE_SKEY,F_CORE_INVESTMENT_COMPANY_IND,F_FINANCIAL_ENTITY_IND,F_REGULATED_FIN_ENTITY_IND,N_CUST_SKEY,N_COUNTERPARTY_TYPE_SKEY,N_PROD_SKEY,D_EXPOSURE_END_DATE,F_INTERNAL_CUST_IND,N_COVERED_RWA_UL,N_CURR_12M_ECL,N_EFF_MATURITY,N_EL_AMOUNT,N_EXPOSURE_AMOUNT,N_EXP_COVERED_AMT,N_EXP_UNCOVERED_AMT,N_GENERAL_PROVISION_AMT,N_GROUP_ASSET_SIZE,N_LOSS_ALLOWANCE_LIFE_ECL,N_MORTGAGE_LENDING_VALUE,N_ORIGINAL_MATURITY,N_PRE_MITIGATION_RWA_EL,N_RESIDUAL_MATURITY,N_RUN_SKEY,N_RWA_EL_AMT,N_RWA_UL_AMT,N_CUST_ANNUAL_SALES,N_SANCTIONED_LIMIT,N_SHAREHOLDING_PERCENT,N_UNCOVERED_RWA_UL,N_UNDRAWN_AMOUNT,V_DATA_SOURCE,V_EXP_RCY_CODE,N_ENTITY_SKEY,F_CASH_POOL_DAILY_TRANSFER,F_CASH_POOL_LEGAL_ENFORCEABLE,F_CREDIT_IMPAIRMENT_FLAG,F_EXP_PRIORITY_SECTOR,F_EXP_TREATED_AS_HIGH_RISK,F_FINANCIAL_ASSET_IFRS9_FLAG,F_PREF_TREATMENT_FLAG,F_RW_BY_DISCRETION,N_CCF_OWN_ESTIMATE,N_CCF_OWN_ESTIMATE_DRAWN,N_DVA_AMOUNT,N_EL_BEST_ESTIMATE_PERCENT,N_LGD_PERCENT_PRE_CRM,N_LONG_RUN_WEIGHTED_AVG_LGD,N_PD_PERCENT,N_PROVISION_AMOUNT,V_APPROACH_TYPE,N_CAP_APPROACH_TYPE_SKEY,N_CAP_RECORD_TYPE_SKEY,V_RECORD_TYPE,N_BASEL_PARTY_GRADE_SKEY,N_STD_COUNTERPARTY_TYPE_SKEY,N_BASEL_TXN_TYPE_SKEY,N_BASEL_PROD_TYPE_SKEY,N_RUN_PARAMETER_SETUP_SKEY,N_SEC_POOL_SKEY,D_EXPOSURE_START_DATE,F_AUTO_CANCELLATION_FLAG,F_ELIGIBLE_PROTECTION_IND,F_EXP_DEFAULTED_FLAG,F_EXP_HELD_AT_FAIR_VALUE,F_EXP_REV_FLAG,F_PAST_DUE_FLAG,F_REG_CAP_INVST_IND,F_RESTRUCTURED_IND,F_SECURED_IND,F_SECURITIZED_FLAG,F_SENIOR_CLAIM_FLAG,F_UNCOND_CANCELLED_EXP_IND,N_DELQ_DAYS,N_LOAD_RUN_ID,V_PRODUCT_BOOK_CODE,V_CCY_CODE)SELECT  /*+PARALLEL (4)*/ to_char(DIM_COUNTRY.N_COUNTRY_SKEY),to_char(DIM_CREDIT_LINE.N_CREDIT_LINE_SKEY),to_char(DIM_CREDIT_STATUS.N_CREDIT_STATUS_SKEY),to_char(DIM_DATES.N_DATE_SKEY),to_char(DIM_EXPOSURE.N_ACCT_SKEY),to_char(DIM_GAAP.N_GAAP_SKEY),to_char(DIM_ISSUE.N_ISSUE_SKEY),to_char(DIM_OCCUPANCY_TYPE.N_OCCUPANCY_TYPE_SKEY),DIM_PARTY.F_CORE_INVESTMENT_COMPANY_IND,DIM_PARTY.F_FINANCIAL_ENTITY_IND,DIM_PARTY.F_REGULATED_FIN_ENTITY_IND,to_char(DIM_PARTY.N_PARTY_SKEY),to_char(DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY),to_char(DIM_PRODUCT.N_PROD_SKEY),case when d_revised_renewal_date is NULL THEN d_actual_renewal_date else d_revised_renewal_date end,CASE  WHEN FCT_ENTITY_INFO_CUST.V_PARTY_ID IS NOT NULL AND DIM_BASEL_CAP_CONSL_APPR_CUST.v_basel_cap_consl_appr_code IN ('FLCS', 'PRCS','FAGR','PRAGR')  THEN   'Y' ELSE 'N'   END,0,CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_STD END,CASE WHEN FSI_ACCT_MODELING_INFO.N_EFF_MATURITY IS NULL THEN DAYS_BETWEEN(STG_OD_ACCOUNTS.FIC_MIS_DATE, COALESCE(STG_OD_ACCOUNTS.D_REVISED_RENEWAL_DATE, STG_OD_ACCOUNTS.D_ACTUAL_RENEWAL_DATE), STG_OD_ACCOUNTS.V_DAY_COUNT_IND) ELSE FSI_ACCT_MODELING_INFO.N_EFF_MATURITY END,0,FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE*(CASE WHEN STG_OD_ACCOUNTS.N_EOP_BAL > 0 THEN STG_OD_ACCOUNTS.N_EOP_BAL ELSE 0 END),STG_OD_ACCOUNTS.N_GUARANTEED_AMT,0,FSI_ACCT_MODELING_INFO.N_STAGE_I_ALLOWANCES + FSI_ACCT_MODELING_INFO.N_STAGE_II_ALLOWANCES,FSI_CAP_PARTY_FINANCIALS.N_GROUP_ASSET_SIZE *B_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_LOSS_ALLOWANCE_LIFE_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_LOSS_ALLOWANCE_LIFE_ECL_STD END,FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE*STG_OD_ACCOUNTS.N_MORTGAGE_LENDING_VALUE,DAYS_BETWEEN(STG_OD_ACCOUNTS.D_OPEN_DATE, CASE WHEN STG_OD_ACCOUNTS.D_REVISED_RENEWAL_DATE IS NULL THEN STG_OD_ACCOUNTS.D_ACTUAL_RENEWAL_DATE ELSE STG_OD_ACCOUNTS.D_REVISED_RENEWAL_DATE END,STG_OD_ACCOUNTS.V_DAY_COUNT_IND),0,DAYS_BETWEEN(STG_OD_ACCOUNTS.FIC_MIS_DATE, COALESCE(STG_OD_ACCOUNTS.D_REVISED_RENEWAL_DATE, STG_OD_ACCOUNTS.D_ACTUAL_RENEWAL_DATE), STG_OD_ACCOUNTS.V_DAY_COUNT_IND),'870',0,0,FSI_CAP_PARTY_FINANCIALS.N_SALES_AMT* A_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,(STG_OD_ACCOUNTS.N_SANCTIONED_LIMIT * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE),CASE WHEN DIM_BASEL_CAP_CONSL_APPR.v_basel_cap_consl_appr_code = 'PRCS' THEN FCT_ENTITY_INFO.n_shareholding_percent ELSE 1 END,0,FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE*(case when (n_sanctioned_limit - n_eop_bal)>=0 then (n_sanctioned_limit - n_eop_bal) else 0 end),'STG_OD_ACCOUNTS',RUN_EXE_PARAMETERS_RCY.V_PARAM_VALUE_CODE,to_char(FCT_ENTITY_INFO.N_ENTITY_SKEY),FSI_ACCT_MODELING_INFO.F_CASH_POOL_DAILY_TRANSFER,FSI_ACCT_MODELING_INFO.F_CASH_POOL_LEGAL_ENFORCEABLE,FSI_ACCT_MODELING_INFO.F_CREDIT_IMPAIRMENT_FLAG,FSI_ACCT_MODELING_INFO.F_EXP_PRIORITY_SECTOR,FSI_ACCT_MODELING_INFO.F_EXP_TREATED_AS_HIGH_RISK,FSI_ACCT_MODELING_INFO.F_FINANCIAL_ASSET_IFRS9_FLAG,FSI_ACCT_MODELING_INFO.F_PREF_TREATMENT_FLAG,FSI_ACCT_MODELING_INFO.F_RW_BY_DISCRETION,to_char(FSI_ACCT_MODELING_INFO.N_CCF_OWN_ESTIMATE),to_char(FSI_ACCT_MODELING_INFO.N_CCF_OWN_ESTIMATE_DRAWN),to_char(FSI_ACCT_MODELING_INFO.N_DVA_AMOUNT),to_char(FSI_ACCT_MODELING_INFO.N_EL_BEST_ESTIMATE_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LGD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LONG_RUN_WEIGHTED_AVG_LGD),to_char(FSI_ACCT_MODELING_INFO.N_PD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_PROVISION_AMOUNT),FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE,to_char(FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY),to_char(FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY),FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE,to_char(FSI_PARTY_GRADE_RECLASS.N_BASEL_GRADE_SKEY),to_char(FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY),to_char(FSI_PROD_TXN_TYPE_RECLASS.N_BASEL_TXN_TYPE_SKEY),to_char(FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY),to_char(RUN_PARAMETERS.N_RUN_PARAMETER_SETUP_SKEY),to_char(SEC_POOL_MASTER.N_SEC_POOL_SKEY),STG_OD_ACCOUNTS.D_OPEN_DATE,STG_OD_ACCOUNTS.F_AUTO_CANCELLATION_FLAG,STG_OD_ACCOUNTS.F_ELIGIBLE_PROTECTION_IND,STG_OD_ACCOUNTS.F_EXP_DEFAULTED_FLAG,STG_OD_ACCOUNTS.F_EXP_HELD_AT_FAIR_VALUE,STG_OD_ACCOUNTS.F_EXP_REVOLVING_FLAG,STG_OD_ACCOUNTS.F_PAST_DUE_FLAG,STG_OD_ACCOUNTS.F_REG_CAP_INVST_IND,STG_OD_ACCOUNTS.F_RESTRUCTURED_IND,STG_OD_ACCOUNTS.F_SECURED_IND,STG_OD_ACCOUNTS.F_SECURITIZED_FLAG,STG_OD_ACCOUNTS.F_SENIOR_CLAIM_FLAG,STG_OD_ACCOUNTS.F_UNCOND_CANCELLED_EXP_IND,to_char(STG_OD_ACCOUNTS.N_DELINQUENT_DAYS),to_char(STG_OD_ACCOUNTS.N_LOAD_RUN_ID),STG_OD_ACCOUNTS.V_BOOK_TYPE,STG_OD_ACCOUNTS.V_CCY_CODE FROM STG_OD_ACCOUNTS INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = '870' INNER JOIN DIM_DATES ON STG_OD_ACCOUNTS.FIC_MIS_DATE = to_date('20260331','YYYYMMDD') AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') AND COALESCE(STG_OD_ACCOUNTS.F_SECURITIZED_FLAG, 'N') <> 'Y' AND COALESCE(STG_OD_ACCOUNTS.F_CLOSED_IND, 'N') <> 'Y' INNER JOIN DIM_EXPOSURE ON STG_OD_ACCOUNTS.V_ACCOUNT_NUMBER = DIM_EXPOSURE.V_EXPOSURE_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_EXPOSURE.D_RECORD_START_DATE AND DIM_EXPOSURE.D_RECORD_END_DATE INNER JOIN FCT_ENTITY_INFO ON FCT_ENTITY_INFO.N_RUN_SKEY = '870' AND FCT_ENTITY_INFO.V_ENTITY_CODE = STG_OD_ACCOUNTS.V_LV_CODE AND COALESCE(FCT_ENTITY_INFO.F_CAP_CONSL_ENTITY_IND, 'N') = 'Y' INNER JOIN DIM_BASEL_CAP_CONSL_APPR ON DIM_BASEL_CAP_CONSL_APPR.N_BASEL_CAP_CONSL_APPR_SKEY = FCT_ENTITY_INFO.N_BASEL_CAP_CONSL_APPR_SKEY AND DIM_BASEL_CAP_CONSL_APPR.V_BASEL_CAP_CONSL_APPR_CODE IN ( 'FLCS' ,'PRCS' ) LEFT OUTER JOIN DIM_GAAP ON STG_OD_ACCOUNTS.V_GAAP_CODE = DIM_GAAP.V_GAAP_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_GAAP.D_RECORD_START_DATE AND DIM_GAAP.D_RECORD_END_DATE LEFT OUTER JOIN DIM_CREDIT_STATUS ON STG_OD_ACCOUNTS.V_CREDIT_STATUS_CD = DIM_CREDIT_STATUS.V_CREDIT_STATUS AND to_date('20260331','YYYYMMDD') BETWEEN DIM_CREDIT_STATUS.D_RECORD_START_DATE AND DIM_CREDIT_STATUS.D_RECORD_END_DATE LEFT OUTER JOIN DIM_PARTY ON COALESCE(STG_OD_ACCOUNTS.V_CUST_REF_CODE, 'MSG') = DIM_PARTY.V_PARTY_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY.D_RECORD_START_DATE AND DIM_PARTY.D_RECORD_END_DATE INNER JOIN DIM_PARTY_TYPE ON COALESCE(DIM_PARTY.V_PARTY_TYPE, 'MSG') = DIM_PARTY_TYPE.V_PARTY_TYPE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY_TYPE.D_RECORD_START_DATE AND DIM_PARTY_TYPE.D_RECORD_END_DATE LEFT OUTER JOIN DIM_ISSUE ON COALESCE(STG_OD_ACCOUNTS.V_ACCOUNT_NUMBER, DIM_EXPOSURE.V_EXPOSURE_ID) = DIM_ISSUE.V_ISSUE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ISSUE.D_RECORD_START_DATE AND DIM_ISSUE.D_RECORD_END_DATE LEFT OUTER JOIN DIM_PRODUCT ON STG_OD_ACCOUNTS.V_PROD_CODE = DIM_PRODUCT.V_PROD_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PRODUCT.D_RECORD_START_DATE AND DIM_PRODUCT.D_RECORD_END_DATE LEFT OUTER JOIN DIM_LOB ON STG_OD_ACCOUNTS.V_LOB_CODE = DIM_LOB.V_LOB_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_LOB.D_RECORD_START_DATE AND DIM_LOB.D_RECORD_END_DATE LEFT OUTER JOIN DIM_NETTING_AGREEMENT ON STG_OD_ACCOUNTS.V_NETTING_AGREEMENT_CODE = DIM_NETTING_AGREEMENT.V_NETTING_AGREEMENT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_NETTING_AGREEMENT.D_RECORD_START_DATE AND DIM_NETTING_AGREEMENT.D_RECORD_END_DATE LEFT OUTER JOIN DIM_GEOGRAPHY ON COALESCE(DIM_PARTY.V_BRANCH_CODE, 'MSG') = DIM_GEOGRAPHY.V_ACCT_BRANCH_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_GEOGRAPHY.D_RECORD_START_DATE AND DIM_GEOGRAPHY.D_RECORD_END_DATE LEFT OUTER JOIN DIM_INDUSTRY ON DIM_INDUSTRY.V_D_CUST_INDUSTRY = COALESCE(DIM_PARTY.V_INDUSTRY_CODE, 'MSG') AND to_date('20260331','YYYYMMDD') BETWEEN DIM_INDUSTRY.D_RECORD_START_DATE AND DIM_INDUSTRY.D_RECORD_END_DATE LEFT OUTER JOIN SEC_POOL_MASTER ON SEC_POOL_MASTER.V_SEC_POOL_ID = STG_OD_ACCOUNTS.V_SEC_POOL_ID AND to_date('20260331','YYYYMMDD') BETWEEN SEC_POOL_MASTER.D_RECORD_START_DATE AND SEC_POOL_MASTER.D_RECORD_END_DATE LEFT OUTER JOIN FSI_CAP_PARTY_FINANCIALS ON FSI_CAP_PARTY_FINANCIALS.N_RUN_SKEY = '870' AND FSI_CAP_PARTY_FINANCIALS.N_MIS_DATE_SKEY = TO_NUMBER(TO_CHAR(to_date('20260331','YYYYMMDD'), 'YYYYMMDD')) AND FSI_CAP_PARTY_FINANCIALS.N_PARTY_SKEY = DIM_PARTY.N_PARTY_SKEY LEFT OUTER JOIN RUN_EXE_PARAMETERS ON RUN_EXE_PARAMETERS.N_RUN_SKEY = '870' AND RUN_EXE_PARAMETERS.V_PARAM_ID = 'LE' LEFT JOIN DIM_ORG_STRUCTURE ON DIM_ORG_STRUCTURE.V_ENTITY_CODE = RUN_EXE_PARAMETERS.V_PARAM_VALUE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ORG_STRUCTURE.D_RECORD_START_DATE AND DIM_ORG_STRUCTURE.D_RECORD_END_DATE LEFT OUTER JOIN RUN_EXE_PARAMETERS RUN_EXE_PARAMETERS_RCY ON RUN_EXE_PARAMETERS_RCY.N_RUN_SKEY = '870' AND RUN_EXE_PARAMETERS_RCY.V_PARAM_ID = 'RCY' LEFT OUTER JOIN DIM_LOCATION ON DIM_LOCATION.V_LOCATION_CODE = DIM_PARTY.V_LOCATION_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_LOCATION.D_RECORD_START_DATE AND DIM_LOCATION.D_RECORD_END_DATE LEFT OUTER JOIN FSI_REG_PROD_TYPE_RECLASS ON FSI_REG_PROD_TYPE_RECLASS.N_MIS_DATE_SKEY = TO_NUMBER(TO_CHAR(to_date('20260331','YYYYMMDD'), 'YYYYMMDD')) AND FSI_REG_PROD_TYPE_RECLASS.N_RUN_SKEY = '870' AND FSI_REG_PROD_TYPE_RECLASS.N_PROD_SKEY = DIM_PRODUCT.N_PROD_SKEY LEFT OUTER JOIN DIM_BASEL_PRODUCT_TYPE ON DIM_BASEL_PRODUCT_TYPE.N_BASEL_PROD_TYPE_SKEY = FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY LEFT OUTER JOIN FSI_PARTY_TYPE_CLASSIFICATION ON FSI_PARTY_TYPE_CLASSIFICATION.N_MIS_DATE_SKEY = TO_NUMBER(TO_CHAR(to_date('20260331','YYYYMMDD'), 'YYYYMMDD')) AND FSI_PARTY_TYPE_CLASSIFICATION.N_RUN_SKEY = '870' AND FSI_PARTY_TYPE_CLASSIFICATION.N_PARTY_TYPE_SKEY = DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY LEFT OUTER JOIN DIM_BUSINESS_UNIT ON STG_OD_ACCOUNTS.V_BUSINESS_UNIT_CODE = DIM_BUSINESS_UNIT.V_BUSINESS_UNIT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_BUSINESS_UNIT.D_RECORD_START_DATE AND DIM_BUSINESS_UNIT.D_RECORD_END_DATE LEFT OUTER JOIN DIM_CREDIT_LINE ON STG_OD_ACCOUNTS.V_LINE_NUMBER = DIM_CREDIT_LINE.V_CREDIT_LINE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_CREDIT_LINE.D_RECORD_START_DATE AND DIM_CREDIT_LINE.D_RECORD_END_DATE LEFT OUTER JOIN FSI_CAP_CURRENCY_CONVERSION ON FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = TO_NUMBER(TO_CHAR(to_date('20260331','YYYYMMDD'), 'YYYYMMDD')) AND DIM_RUN.N_RUN_SKEY = FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = STG_OD_ACCOUNTS.V_CCY_CODE LEFT OUTER JOIN FSI_CAP_CURRENCY_CONVERSION A_FSI_CAP_CURRENCY_CONVERSION ON A_FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_RUN.N_RUN_SKEY = A_FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND A_FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = FSI_CAP_PARTY_FINANCIALS.V_CCY_CODE LEFT OUTER JOIN FSI_CAP_CURRENCY_CONVERSION B_FSI_CAP_CURRENCY_CONVERSION ON B_FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_RUN.N_RUN_SKEY = B_FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND B_FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = FSI_CAP_PARTY_FINANCIALS.V_GROUP_CCY_CODE LEFT OUTER JOIN FSI_ACCT_MODELING_INFO ON FSI_ACCT_MODELING_INFO.V_EXPOSURE_ID = DIM_EXPOSURE.V_EXPOSURE_ID AND to_date('20260331','YYYYMMDD') BETWEEN FSI_ACCT_MODELING_INFO.D_RECORD_START_DATE AND FSI_ACCT_MODELING_INFO.D_RECORD_END_DATE LEFT OUTER JOIN FSI_CAP_RUN_EXE_PARAMETERS ON DIM_RUN.N_RUN_SKEY = FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY AND TO_NUMBER(TO_CHAR(to_date('20260331','YYYYMMDD'), 'YYYYMMDD')) = FSI_CAP_RUN_EXE_PARAMETERS.N_MIS_DATE_SKEY LEFT OUTER JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_MIS_DATE_SKEY = TO_NUMBER(TO_CHAR(to_date('20260331','YYYYMMDD'), 'YYYYMMDD')) AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = '870' AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'NONSEC' LEFT OUTER JOIN RUN_PARAMETERS ON RUN_PARAMETERS.N_MIS_DATE_SKEY = TO_NUMBER(TO_CHAR(to_date('20260331','YYYYMMDD'), 'YYYYMMDD')) AND RUN_PARAMETERS.N_RUN_SKEY = '870' AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY = RUN_PARAMETERS.N_RUN_PARAMETER_SKEY LEFT OUTER JOIN DIM_COUNTRY ON COALESCE(STG_OD_ACCOUNTS.V_COUNTRY_CODE, 'MSG') = DIM_COUNTRY.V_COUNTRY_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_COUNTRY.D_RECORD_START_DATE AND DIM_COUNTRY.D_RECORD_END_DATE LEFT OUTER JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE = FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE LEFT OUTER JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'BNK_NON_SEC_EXP' LEFT OUTER JOIN DIM_OCCUPANCY_TYPE ON DIM_OCCUPANCY_TYPE.V_OCCUPANCY_TYPE_CD = STG_OD_ACCOUNTS.V_OCCUPANCY_CD AND to_date('20260331','YYYYMMDD') BETWEEN DIM_OCCUPANCY_TYPE.D_RECORD_START_DATE AND DIM_OCCUPANCY_TYPE.D_RECORD_END_DATE LEFT OUTER JOIN FSI_PARTY_GRADE_RECLASS ON FSI_PARTY_GRADE_RECLASS.N_PARTY_SKEY = DIM_PARTY.N_PARTY_SKEY AND FSI_PARTY_GRADE_RECLASS.N_RUN_SKEY = '870' AND FSI_PARTY_GRADE_RECLASS.N_MIS_DATE_SKEY = TO_NUMBER(TO_CHAR(to_date('20260331','YYYYMMDD'), 'YYYYMMDD')) AND FSI_PARTY_GRADE_RECLASS.N_STANDARD_PARTY_TYPE_SKEY = FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY LEFT OUTER JOIN FCT_ENTITY_INFO FCT_ENTITY_INFO_CUST ON FCT_ENTITY_INFO.V_PARTY_ID = STG_OD_ACCOUNTS.V_CUST_REF_CODE AND FCT_ENTITY_INFO_CUST.N_RUN_SKEY = '870' AND FCT_ENTITY_INFO_CUST.N_MIS_DATE_SKEY = TO_NUMBER(TO_CHAR(to_date('20260331','YYYYMMDD'), 'YYYYMMDD')) AND FCT_ENTITY_INFO_CUST.F_CAP_CONSL_ENTITY_IND = 'Y' LEFT OUTER JOIN DIM_BASEL_CAP_CONSL_APPR DIM_BASEL_CAP_CONSL_APPR_CUST ON DIM_BASEL_CAP_CONSL_APPR_CUST.N_BASEL_CAP_CONSL_APPR_SKEY = FCT_ENTITY_INFO_CUST.N_BASEL_CAP_CONSL_APPR_SKEY AND DIM_BASEL_CAP_CONSL_APPR_CUST.V_BASEL_CAP_CONSL_APPR_CODE IN ( 'FLCS' ,'PRCS' ,'FAGR' ,'PRAGR' ) LEFT JOIN FSI_CAP_ACCOUNT_PORTFOLIO_MAP ON FSI_CAP_ACCOUNT_PORTFOLIO_MAP.N_RUN_SKEY = '870' AND FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY = FSI_CAP_ACCOUNT_PORTFOLIO_MAP.N_CAP_APPROACH_TYPE_SKEY AND DIM_EXPOSURE.V_EXPOSURE_ID = FSI_CAP_ACCOUNT_PORTFOLIO_MAP.V_ACCOUNT_NUMBER AND DIM_GAAP.V_GAAP_CODE = FSI_CAP_ACCOUNT_PORTFOLIO_MAP.V_GAAP_CODE AND FSI_CAP_ACCOUNT_PORTFOLIO_MAP.FIC_MIS_DATE = to_date('20260331','YYYYMMDD') AND STG_OD_ACCOUNTS.N_LOAD_RUN_ID = FSI_CAP_ACCOUNT_PORTFOLIO_MAP.N_LOAD_RUN_ID LEFT OUTER JOIN